### Optional Properties

Optional properties in interfaces may or may not be present on an object.

### Syntax

```typescript
interface User {
  name: string;
  email?: string;
  phone?: string;
}

// OK - only required properties
const user1: User = { name: "Alice" };

// OK - includes optional properties
const user2: User = {
  name: "Bob",
  email: "bob@example.com"
};
```

### Accessing Optional Properties

Optional properties have type `T | undefined` when accessed:

```typescript
function getEmail(user: User): string | undefined {
  return user.email;
}
```

### Narrowing Optional Properties

```typescript
function displayContact(user: User): string {
  if (user.email) {
    return `Email: ${user.email}`;
  }
  if (user.phone) {
    return `Phone: ${user.phone}`;
  }
  return "No contact info";
}
```

### Optional vs undefined

```typescript
interface Config {
  timeout?: number;
}

// Both are valid
const c1: Config = {};
const c2: Config = { timeout: undefined };
```

### Required with undefined

```typescript
interface Config {
  timeout: number | undefined; // Must be explicitly set
}

const c: Config = {}; // Error: timeout is required
const c2: Config = { timeout: undefined }; // OK
```

> **Key Point:** Use `?` for properties that may be completely absent.

codeExample:
interface Profile {
  username: string;
  bio?: string;
  avatar?: string;
  socialLinks?: {
    twitter?: string;
    github?: string;
  };
}

function renderProfile(profile: Profile): string {
  const parts: string[] = [`Username: ${profile.username}`];

  if (profile.bio) {
    parts.push(`Bio: ${profile.bio}`);
  }

  const twitter = profile.socialLinks?.twitter;
  if (twitter) {
    parts.push(`Twitter: ${twitter}`);
  }

  return parts.join("\n");
}
